import React from 'react';

const Footer = () => {
  return (
    <footer style={styles.footerContainer}>
      <div style={styles.footerContent}>
        {/* Sección 1: thirsty for more? */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>thirsty for more?</h3>
          <div style={styles.linksColumn}>
            <ul style={styles.linkList}>
              <li><a href="#" style={styles.link}>shop</a></li>
              <li><a href="#" style={styles.link}>learn</a></li>
              <li><a href="#" style={styles.link}>reviews</a></li>
              <li><a href="#" style={styles.link}>gift cards</a></li>
              <li><a href="#" style={styles.link}>buy with fsa / hsa</a></li>
            </ul>
            <ul style={styles.linkList}>
              <li><a href="#" style={styles.link}>rewards</a></li>
              <li><a href="#" style={styles.link}>refer-a-friend</a></li>
              <li><a href="#" style={styles.link}>join the team</a></li>
              <li><a href="#" style={styles.link}>about us</a></li>
            </ul>
          </div>
        </div>

        {/* Sección 2: find us in stores / the exclusive email club / social */}
        <div style={styles.sectionCenter}>
          <h3 style={styles.sectionTitle}>find us in stores near you</h3>
          <button style={styles.storeLocatorButton}>STORE LOCATOR</button>
          <h3 style={{ ...styles.sectionTitle, marginTop: '30px' }}>the exclusive email club</h3>
          <p style={styles.emailClubText}>give us those e-digits. you won't regret it.</p>
          <div style={styles.emailInputContainer}>
            <input type="email" placeholder="your email" style={styles.emailInput} />
            <button style={styles.emailSubmitButton}>&rarr;</button>
          </div>
          <div style={styles.socialIcons}>
            {/* Asegúrate de tener Font Awesome o reemplazar estos iconos */}
            <a href="#" style={styles.socialIcon}><i className="fab fa-facebook-f"></i></a>
            <a href="#" style={styles.socialIcon}><i className="fab fa-instagram"></i></a>
            <a href="#" style={styles.socialIcon}><i className="fab fa-tiktok"></i></a>
          </div>
        </div>

        {/* Sección 3: need help? */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>need help?</h3>
          <ul style={styles.linkListSingle}>
            <li><a href="#" style={styles.link}>shipping & returns</a></li>
            <li><a href="#" style={styles.link}>contact us</a></li>
            <li><a href="#" style={styles.link}>wholesale</a></li>
            <li><a href="#" style={styles.link}>privacy</a></li>
            <li><a href="#" style={styles.link}>terms of service</a></li>
            <li><a href="#" style={styles.link}>frequently asked questions</a></li>
            <li><a href="#" style={styles.link}>sitemap</a></li>
          </ul>
        </div>
      </div>
      {/* Barra inferior "FREE VARIETY PACK" - Descomenta si la necesitas */}
      {/* <div style={styles.bottomBar}>
        <span style={styles.bottomBarText}>FREE VARIETY PACK</span>
        <button style={styles.bottomBarClose}>&times;</button>
      </div> */}
    </footer>
  );
};

const styles = {
  footerContainer: {
    // Fondo con la imagen de footer2.png
    backgroundImage: "url('/media/footer2.png')", // Ruta relativa a la carpeta 'public'
    backgroundSize: 'cover', // Cubrir toda el área
    backgroundPosition: 'center', // Centrar la imagen
    backgroundRepeat: 'no-repeat', // No repetir la imagen
    backgroundColor: '#F8F6F1', // Color de fondo de respaldo si la imagen no carga o es transparente
    padding: '60px 20px',
    color: '#333',
    fontFamily: "'Poppins', sans-serif",
    borderTop: '1px solid #eee',
    boxShadow: '0 -2px 10px rgba(0,0,0,0.05)', // Sombra sutil en la parte superior del footer
  },
  footerContent: {
    display: 'flex',
    justifyContent: 'space-around',
    flexWrap: 'wrap', // Permitir que las columnas se envuelvan en pantallas pequeñas
    maxWidth: '1200px', // Ancho máximo del contenido del footer
    margin: '0 auto', // Centrar el contenido
    gap: '40px', // Espacio entre las secciones (columnas)
  },
  section: {
    flex: '1 1 280px', // Flex-grow, flex-shrink, basis (para tamaño flexible)
    minWidth: '200px', // Ancho mínimo de cada sección
  },
  sectionCenter: {
    flex: '1 1 350px',
    minWidth: '250px',
    textAlign: 'center',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
  },
  sectionTitle: {
    fontSize: '1.2rem',
    fontWeight: 'bold',
    marginBottom: '20px',
    textTransform: 'uppercase',
  },
  linksColumn: {
    display: 'flex',
    justifyContent: 'space-between',
    gap: '20px', // Espacio entre las dos sub-columnas de enlaces
  },
  linkList: {
    listStyle: 'none',
    padding: 0,
    margin: 0,
  },
  linkListSingle: { // Para la columna de 'need help?'
    listStyle: 'none',
    padding: 0,
    margin: 0,
    lineHeight: '1.8', // Espaciado entre elementos de la lista
  },
  link: {
    textDecoration: 'none',
    color: '#333',
    fontSize: '0.95rem',
    transition: 'color 0.3s ease',
    '&:hover': {
      color: '#166D3B', // Color de hover verde
    },
  },
  storeLocatorButton: {
    backgroundColor: '#333',
    color: 'white',
    border: 'none',
    padding: '12px 25px',
    borderRadius: '5px',
    cursor: 'pointer',
    fontSize: '0.9rem',
    fontWeight: 'bold',
    textTransform: 'uppercase',
    marginTop: '10px',
    transition: 'background-color 0.3s ease',
    '&:hover': {
      backgroundColor: '#166D3B',
    },
  },
  emailClubText: {
    fontSize: '0.9rem',
    color: '#666',
    marginBottom: '15px',
  },
  emailInputContainer: {
    display: 'flex',
    width: '80%',
    maxWidth: '300px',
    borderBottom: '2px solid #333',
    paddingBottom: '5px',
    marginBottom: '30px',
  },
  emailInput: {
    flexGrow: 1,
    border: 'none',
    outline: 'none',
    backgroundColor: 'transparent',
    fontSize: '1rem',
    color: '#333',
    padding: '5px 0',
